    const flowerToggle = document.createElement('button');
    flowerToggle.type = 'button';
    flowerToggle.className = 'editor-manual-flower-toggle';
    flowerToggle.id = 'manualFlowerToggle';
    flowerToggle.onclick = () => toggleManualFlowerPanel();

    flowerHeader.appendChild(flowerTitle);
    flowerHeader.appendChild(flowerToggle);
    flowerSection.appendChild(flowerHeader);

    const flowerContent = document.createElement('div');
    flowerContent.className = 'editor-manual-flower-content';
    flowerContent.id = 'editorManualFlowerContent';

