function normalizeImportedBoardMatrix(rawBoardData) {
    if (!Array.isArray(rawBoardData) || rawBoardData.length === 0) return null;
    if (!Array.isArray(rawBoardData[0]) || rawBoardData[0].length === 0) return null;
    const width = rawBoardData[0].length;
    const normalized = [];
    for (const row of rawBoardData) {
        if (!Array.isArray(row) || row.length !== width) return null;
        const normalizedRow = row.map((value) => {
            const numericValue = Number(value);
            if (!Number.isFinite(numericValue)) return EMPTY_CELL_ID;
            return Math.trunc(numericValue);
        });
        normalized.push(normalizedRow);
    }
    return normalized;
}

function extractBoardFromParsedClipboardData(parsedData) {
    if (Array.isArray(parsedData)) {
        if (parsedData.length > 0 && Array.isArray(parsedData[0])) {
            return {
                boardData: parsedData,
                direction: null,
                manualFaceBindings: {}
            };
        }
        if (parsedData.length > 0 && parsedData[0] && typeof parsedData[0] === 'object') {
            const firstItem = parsedData[0];
            if (Array.isArray(firstItem.zhenxing) || Array.isArray(firstItem.board) || Array.isArray(firstItem.boardData)) {
                return {
                    boardData: firstItem.zhenxing || firstItem.board || firstItem.boardData,
                    direction: Number(firstItem.fangxiang ?? firstItem.direction),
                    manualFaceBindings: firstItem.manualFaceBindings || {}
                };
            }
        }
    }
    if (parsedData && typeof parsedData === 'object') {
        if (Array.isArray(parsedData.zhenxing) || Array.isArray(parsedData.board) || Array.isArray(parsedData.boardData)) {
            return {
                boardData: parsedData.zhenxing || parsedData.board || parsedData.boardData,
                direction: Number(parsedData.fangxiang ?? parsedData.direction),
                manualFaceBindings: parsedData.manualFaceBindings || {}
            };
        }
        if (Array.isArray(parsedData.levels) && parsedData.levels.length > 0) {
            const firstLevel = parsedData.levels[0];
            if (firstLevel && (Array.isArray(firstLevel.zhenxing) || Array.isArray(firstLevel.board) || Array.isArray(firstLevel.boardData))) {
                return {
                    boardData: firstLevel.zhenxing || firstLevel.board || firstLevel.boardData,
                    direction: Number(firstLevel.fangxiang ?? firstLevel.direction),
                    manualFaceBindings: firstLevel.manualFaceBindings || {}
                };
            }
        }
    }
    return null;
}

function parseBoardFromClipboardText(clipboardText) {
    if (typeof clipboardText !== 'string') return null;
    const text = clipboardText.trim();
    if (!text) return null;

    const tryParseJson = (jsonText) => {
        try {
            const parsed = JSON.parse(jsonText);
            return extractBoardFromParsedClipboardData(parsed);
        } catch (_) {
            return null;
        }
    };

    const directParsed = tryParseJson(text);
    if (directParsed) return directParsed;

    const tabSegments = text.split('\t');
    for (const segment of tabSegments) {
        const candidate = tryParseJson(segment.trim());
        if (candidate) return candidate;
    }

    const arrayStart = text.indexOf('[[');
    const arrayEnd = text.lastIndexOf(']]');
    if (arrayStart !== -1 && arrayEnd !== -1 && arrayEnd > arrayStart) {
        const candidateText = text.slice(arrayStart, arrayEnd + 2);
        const candidate = tryParseJson(candidateText);
        if (candidate) return candidate;
    }
    return null;
}

async function importBoardFromClipboard() {
    if (isSimulatingPlayGames || isBatchCampaignRunning || isBatchGenerating) {
        alert('当前有任务进行中，请稍后再试。');
        return;
    }
    if (!navigator.clipboard || typeof navigator.clipboard.readText !== 'function') {
        alert('当前环境不支持读取剪贴板。');
        return;
    }

    let clipboardText = '';
    try {
        clipboardText = await navigator.clipboard.readText();
    } catch (error) {
        console.error('Failed to read clipboard:', error);
        alert('读取剪贴板失败，请检查浏览器权限。');
        return;
    }

    const parsedPayload = parseBoardFromClipboardText(clipboardText);
    const boardData = normalizeImportedBoardMatrix(parsedPayload?.boardData);
    if (!boardData) {
        alert('剪贴板中未找到有效阵型数据。');
        return;
    }
    const fallbackDirection = parseInt(
        document.querySelector('input[name="direction"]:checked')?.value || 0,
        10
    );
    const loaded = loadBoardDataIntoEditor(
        boardData,
        Number.isFinite(Number(parsedPayload?.direction))
            ? Number(parsedPayload.direction)
            : fallbackDirection,
        parsedPayload?.manualFaceBindings || {},
        { levelId: null }
    );
    if (!loaded) return;

    const info = document.getElementById('info');
    if (info) info.textContent = `已读取阵型：${boardData[0].length}×${boardData.length}`;
}

function loadBoardDataIntoEditor(
    boardData,
    direction = 0,
    loadedManualFaceBindings = {},
    options = {}
) {
    const normalizedBoard = normalizeImportedBoardMatrix(boardData);
    if (!normalizedBoard) {
        alert('阵型数据无效。');
        return false;
    }
    const height = normalizedBoard.length;
    const width = normalizedBoard[0].length;
    if (width < 6 || width > 10 || height < 6 || height > 14) {
        alert('读取失败：阵型尺寸超出范围（宽度 6-10，高度 6-14）。');
        return false;
    }

    const safeDirection = Number.isFinite(Number(direction))
        ? Math.max(0, Math.min(8, Math.round(Number(direction))))
        : 0;
    selectDirection(safeDirection);
    setSliderControlValue('width', 'widthValue', width, 0);
    setSliderControlValue('height', 'heightValue', height, 0);
    calculatePool();
    generateBoard();

    filledCells = cloneBoardData(normalizedBoard);
    const activeLayer = getActiveBoardLayer();
    activeLayer.width = width;
    activeLayer.height = height;
    activeLayer.boardData = filledCells;
    manualFaceBindings = normalizeManualFaceBindings(loadedManualFaceBindings, normalizedBoard);
    syncBoardDisplayByData(filledCells);
    updateResultSummaryByBoard(filledCells);
    updateLevelStats(safeDirection);
    selectEditorTool(selectedEditorTool);
    renderBoardLayerList();
    renderBoardLayerPreviewStack();
    if (Object.prototype.hasOwnProperty.call(options, 'levelId')) {
        setCurrentSimulatorLevelId(options.levelId);
    }
    setTimeout(scaleBoard, 100);
    return true;
}

function getNextSavedLevelId() {
    if (!Array.isArray(savedLevels) || savedLevels.length === 0) return 1;
    let maxId = 0;
    for (const item of savedLevels) {
        const itemId = Number(item?.id);
        if (Number.isFinite(itemId) && itemId > maxId) {
            maxId = Math.floor(itemId);
        }
    }
    return maxId + 1;
}

function renumberSavedLevelIdsByOrder() {
    if (!Array.isArray(savedLevels)) return;
    for (let index = 0; index < savedLevels.length; index++) {
        const item = savedLevels[index];
        if (!item || typeof item !== 'object') continue;
        item.id = index + 1;
    }
}

