        '相邻同牌对数': 'match_num',
        'match_num': 'match_num',
        'matchnum': 'match_num',
        '测试局数': 'testnum',
        '模拟局数': 'testnum',
        'testnum': 'testnum',
        'test_num': 'testnum',
        '难度': 'difficulty',
        'difficulty': 'difficulty',
        '跳过': 'jump',
        'jump': 'jump',
        'skip': 'jump',
        '人类模式': 'humanMode',
        'humanmode': 'humanMode',
        'human_mode': 'humanMode',
        '人类模式相邻优先概率': 'humanmode_beside',
        'humanmode_beside': 'humanmode_beside',
        'humanmodebeside': 'humanmode_beside',
        '自动炸弹对数': 'autoBombPairCount',
        '炸弹对数': 'autoBombPairCount',
        'autobombpaircount': 'autoBombPairCount',
        'bombpaircount': 'autoBombPairCount',
        'variable_1': 'Variable_1',
        'variable1': 'Variable_1',
        'variable_2': 'Variable_2',
        'variable2': 'Variable_2',
        'variable_3': 'Variable_3',
        'variable3': 'Variable_3',
        'variable_4': 'Variable_4',
        'variable4': 'Variable_4',
        'variable_5': 'Variable_5',
        'variable5': 'Variable_5',
        '前期配对': 'rhythmEarlyPairRange',
        '前期配对数': 'rhythmEarlyPairRange',
        '前期配对范围': 'rhythmEarlyPairRange',
        '前期配对数范围': 'rhythmEarlyPairRange',
        '前期配对最小': 'rhythmEarlyPairMin',
        '前期配对数最小': 'rhythmEarlyPairMin',
        '前期配对最大': 'rhythmEarlyPairMax',
        '前期配对数最大': 'rhythmEarlyPairMax',
        '前期距离': 'rhythmEarlyDistanceRange',
        '前期路径距离': 'rhythmEarlyDistanceRange',
        '前期距离范围': 'rhythmEarlyDistanceRange',
        '前期路径距离范围': 'rhythmEarlyDistanceRange',
        '前期距离最小': 'rhythmEarlyDistanceMin',
        '前期路径距离最小': 'rhythmEarlyDistanceMin',
        '前期距离最大': 'rhythmEarlyDistanceMax',
        '前期路径距离最大': 'rhythmEarlyDistanceMax',
        '中期配对': 'rhythmMiddlePairRange',
        '中期配对数': 'rhythmMiddlePairRange',
        '中期配对范围': 'rhythmMiddlePairRange',
        '中期配对数范围': 'rhythmMiddlePairRange',
        '中期配对最小': 'rhythmMiddlePairMin',
        '中期配对数最小': 'rhythmMiddlePairMin',
        '中期配对最大': 'rhythmMiddlePairMax',
        '中期配对数最大': 'rhythmMiddlePairMax',
        '中期距离': 'rhythmMiddleDistanceRange',
        '中期路径距离': 'rhythmMiddleDistanceRange',
        '中期距离范围': 'rhythmMiddleDistanceRange',
        '中期路径距离范围': 'rhythmMiddleDistanceRange',
        '中期距离最小': 'rhythmMiddleDistanceMin',
        '中期路径距离最小': 'rhythmMiddleDistanceMin',
        '中期距离最大': 'rhythmMiddleDistanceMax',
        '中期路径距离最大': 'rhythmMiddleDistanceMax',
        '同层概率': 'rhythmSameLayerChance',
        '卡点概率': 'rhythmStuckPairChance',
        '卡点数量': 'rhythmStuckPairCount',
