        '直线连接权重': 'rhythmWeightStraight',
        '1拐权重': 'rhythmWeightOneTurn',
        '1拐连接权重': 'rhythmWeightOneTurn',
        '同向2拐权重': 'rhythmWeightSameTwoTurn',
        '同向二拐权重': 'rhythmWeightSameTwoTurn',
