        fillBoard,
        generateAutoObstacles,
        handleBatchGenerateFileChange,
        handleBatchRunCampaignFileChange,
        handleConfigGroupFileChange,
        handleHumanModeBesidePercentInput,
        handleSavedLevelContextAction,
        handleSavedLevelFileChange,
        importBoardFromClipboard,
        loadSelectedConfigGroup,
        refreshBoardWithPlaceholder,
        restartPlayMode,
        saveCurrentConfigGroup,
        saveCurrentLevelToList,
        saveSavedLevelsToCurrentFile,
        selectDirection,
        setActiveBoardLayer,
        setBoardLayerSize,
        setGameFillMode,
        setGamePlayMode,
        setGameTurnLimitMode,
        setGameLimitMode,
        setGameGoalMode,
        setGameGoalTargetPairs,
        setPlayClickHintMode,
        setPlayDisplayStyle,
        setPlayLinkStyle,
        setPlayOperationMode,
        setVitaMahjongMode,
        simulatePlayGames,
        stepGenerateOrNext,
        toggleBoardBackgroundDropdown,
        togglePlayClickHintMode,
        togglePlayMode,
        togglePlaySettingsPanel,
        toggleStatsLocalHumanMode,
        toggleStepPairExportScope,
        toggleWorkerPoolReuse,
        triggerBatchRunCampaignImport,
        triggerImportConfigGroups,
        triggerImportSavedLevels,
        updateSimulateUiLabels,
        usePlayFreezeTool,
